int dis[405][405], ans[405][405];
struct node {
	int id, st, d;
};
void solve(int CASE)
{
	int n, m, q; cin >> n >> m >> q;
	var g = vector<vector<pii>>(n + 1);
	fa(i, 1, m) {
		int u, v; cin >> u >> v;
		char c; cin >> c;
		int w = (c == '(' ? 1 : -1);
		g[u].pb({ v,w }), g[v].pb({ u,w });
	}
	fa(i, 1, n) {
		fa(j, 0, n)fa(k, 0, n)dis[j][k] = INF;
		var Q = queue<node>();
		Q.push({ i, 0, dis[i][0] = 0 });
		while (Q.size()) {
			var[now, st, d] = Q.front();
			Q.pop();
			if (d > dis[now][st])continue;
			for (const var& [to, w] : g[now]) {
				if (st == 0) {
					if (w < 0 or st + w > n)continue;
					if (dis[to][st + w] > dis[now][st] + 1) {
						dis[to][st + w] = dis[now][st] + 1;
						Q.push({ to, st + w, dis[to][st + w] });
					}
				}
				else {
					if (st + w > n)continue;
					if (dis[to][st + w] > dis[now][st] + 1) {
						dis[to][st + w] = dis[now][st] + 1;
						Q.push({ to, st + w, dis[to][st + w] });
					}
				}
			}
		}
		fa(j, 1, n)ans[i][j] = dis[j][0];
	}
	while (q--) {
		int x, y; cin >> x >> y;
		if (ans[x][y] >= INF)cout << -1 << endl;
		else cout << ans[x][y] << endl;
	}
	return;
}
